   102â†’
   103â†’		/* should be extended to support comma separated list of
   104â†’		 *	[!]key[=value] parameters, e.g.  -E !foo,bar=567
   105â†’		 */
   106â†’
   107â†’		cvalue = NULL;
   108â†’		if( optarg[0] == '!' ) {
   109â†’			optarg++;
   110â†’		}
   111â†’
   112â†’		control = optarg;
   113â†’		if ( (cvalue = strchr( control, '=' )) != NULL ) {
   114â†’			*cvalue++ = '\0';
   115â†’		}
   116â†’
   117â†’		if (strcasecmp(control, "sasl") == 0) {
   118â†’#if defined(LDAP_API_FEATURES_VERIFY_CREDENTIALS_INTERACTIVE) && defined(HAVE_CYRUS_SASL)
