   120â†’				fprintf(stderr,
   121â†’				    _("SASL option previously specified\n"));
   122â†’				exit(EXIT_FAILURE);
   123â†’			}
   124â†’			if (cvalue == NULL) {
   125â†’				fprintf(stderr,
   126â†’					_("missing mode in SASL option\n"));
   127â†’				exit(EXIT_FAILURE);
   128â†’			}
   129â†’
   130â†’			switch (*cvalue) {
   131â†’			case 'a':
   132â†’			case 'A':
   133â†’				vc_sasl = LDAP_SASL_AUTOMATIC;
   134â†’				break;
   135â†’			case 'i':
   136â†’			case 'I':
   137â†’				vc_sasl = LDAP_SASL_INTERACTIVE;
   138â†’				break;
   139â†’			case 'q':
   140â†’			case 'Q':
   141â†’				vc_sasl = LDAP_SASL_QUIET;
   142â†’				break;
   143â†’			default:
