   249â†’#endif
   250â†’
   251â†’		} else {
   252â†’		    fprintf( stderr, _("Invalid Verify Credentials extension name: %s\n"), control );
   253â†’		    usage();
   254â†’		}
   255â†’		break;
   256â†’
   257â†’	case 'a':  /* request authzid */
   258â†’		req_authzid++;
   259â†’		break;
   260â†’
   261â†’	case 'b':  /* request authzid */
